import type { SdkLanguage } from "./installedSdk.js";
/** Languages whose SDK ships a replay implementation (Go does not). */
export type ReplayLanguage = Exclude<SdkLanguage, "go">;
export type ReplayCapability = "supportsExperimentGroups" | "supportsDatasetId" | "supportsCodeChanges" | "supportsReplayTraceIds" | "supportsInputAdapters";
export type ReplayCapabilities = Record<ReplayCapability, boolean>;
/**
 * The minimum published SDK version at which each replay capability first
 * exists, per language. Derived from the introducing commit for each feature
 * (verified absent in the parent commit, present at the feature commit) and
 * the SDK version baked into that same commit.
 *
 * Capability floors are immutable historical facts (a feature that shipped in
 * 0.13.5 shipped in 0.13.5 forever), so this table is write-once per capability:
 * it only grows a row when a new capability is added, which needs plugin code
 * anyway. Gating on the resolved installed version this way is uniform across
 * all four languages and replaces the per-package-manager dist-file grepping the
 * assistant flow used to run by hand.
 *
 * To pin a floor when adding a capability: pickaxe the option/field token to its
 * introducing commit (`git log -S'<token>' --reverse -- <sdk-dir>`), confirm the
 * parent lacks it, and read the version file at that commit. The floors below
 * were derived and independently re-verified this way. Floors can differ by
 * patch across SDKs (the same feature lands at a different point in each SDK's
 * independent version line), so derive each language separately.
 */
export declare const REPLAY_CAPABILITY_MIN_VERSIONS: Record<ReplayLanguage, Record<ReplayCapability, string>>;
export declare function isReplayLanguage(language: SdkLanguage): language is ReplayLanguage;
/**
 * True when `version` is greater than or equal to `min` (node-semver precedence,
 * including pre-release rules). A null version (couldn't resolve the installed
 * SDK), or one that won't coerce to semver, is treated as not meeting the floor.
 */
export declare function isVersionAtLeast(version: string | null, min: string): boolean;
/**
 * Compute the five replay capabilities for an installed SDK from its resolved
 * version. When the version is unknown (null), every capability is false: the
 * caller surfaces `versionResolved: false` so the agent can fall back to a
 * manual check rather than trusting an all-false result.
 */
export declare function detectReplayCapabilities(language: ReplayLanguage, version: string | null): ReplayCapabilities;
